parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "Invoice Data Extraction Schema",
  "description": "Schema for validating JSON output of invoice data extraction.",
  "properties": {
    "invoice_number": {
      "type": ["string", "null"],
      "description": "The unique identifier for the invoice. Set to null if not available."
    },
    "invoice_date": {
      "type": ["string", "null"],
      "description": "The issue date of the invoice in YYYY-MM-DD format.",
      "pattern": "^\\d{4}-\\d{2}-\\d{2}$"
    },
    "total_amount": {
      "type": ["number", "null"],
      "description": "The total amount due including taxes. Set to null if not available."
    },
    "tax": {
      "type": ["number", "null"],
      "description": "The cumulative total of all tax components. Set to null if not available."
    },
    "tax_breakdown": {
      "type": "array",
      "description": "Individual tax line items found on the invoice.",
      "items": {
        "type": "object",
        "properties": {
          "tax_name": { "type": "string" },
          "amount": { "type": "number" }
        },
        "required": ["tax_name", "amount"],
        "additionalProperties": false
      }
    }
  },
  "required": ["invoice_number", "invoice_date", "total_amount", "tax", "tax_breakdown"],
  "additionalProperties": false
}

